<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Personal Expense Tracker</title>
<style>
  * { box-sizing: border-box; }
  body {
    font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif;
    margin: 0;
    padding: 20px;
    background: #f5f6f8;
    color: #222;
    line-height: 1.4;
  }
  .container {
    max-width: 900px;
    margin: 0 auto;
  }
  h1 {
    font-size: 1.5rem;
    margin: 0 0 16px;
  }
  .panel {
    background: #fff;
    border: 1px solid #e3e5ea;
    border-radius: 8px;
    padding: 16px;
    margin-bottom: 16px;
  }
  .panel h2 {
    font-size: 1.05rem;
    margin: 0 0 12px;
  }
  .grid {
    display: grid;
    gap: 10px;
  }
  label {
    display: block;
    font-size: 0.85rem;
    color: #555;
    margin-bottom: 4px;
  }
  input, select, textarea, button {
    font: inherit;
    padding: 8px 10px;
    border: 1px solid #c9ccd2;
    border-radius: 6px;
    background: #fff;
    color: #222;
    width: 100%;
  }
  input:focus, select:focus, textarea:focus {
    outline: 2px solid #4a7afe;
    outline-offset: -1px;
    border-color: #4a7afe;
  }
  button {
    cursor: pointer;
    background: #4a7afe;
    color: #fff;
    border-color: #4a7afe;
  }
  button:hover { background: #3a66ee; }
  button.secondary {
    background: #fff;
    color: #333;
    border-color: #c9ccd2;
  }
  button.secondary:hover { background: #f0f1f4; }
  .form-grid {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(140px, 1fr));
    gap: 10px;
    align-items: end;
  }
  .form-grid .full { grid-column: 1 / -1; }
  .form-error {
    color: #b00020;
    background: #fde8ea;
    border: 1px solid #f5c4c9;
    padding: 8px 10px;
    border-radius: 6px;
    font-size: 0.9rem;
    margin-top: 10px;
    min-height: 0;
  }
  .form-error:empty { display: none; }
  .summary {
    display: grid;
    grid-template-columns: 1fr 2fr;
    gap: 16px;
  }
  .total-box {
    background: #eef3ff;
    border: 1px solid #d4e0ff;
    border-radius: 8px;
    padding: 14px;
  }
  .total-box .label {
    font-size: 0.8rem;
    color: #555;
    text-transform: uppercase;
    letter-spacing: 0.04em;
  }
  .total-box .value {
    font-size: 1.8rem;
    font-weight: 700;
    margin-top: 4px;
  }
  .cat-list {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(120px, 1fr));
    gap: 8px;
  }
  .cat-total {
    background: #f7f8fa;
    border: 1px solid #e3e5ea;
    border-radius: 6px;
    padding: 8px 10px;
    font-size: 0.85rem;
  }
  .cat-total .cat-name {
    text-transform: capitalize;
    color: #555;
    font-size: 0.78rem;
  }
  .cat-total .cat-amount {
    font-weight: 700;
    display: block;
    margin-top: 2px;
  }
  .filters {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(140px, 1fr));
    gap: 10px;
    align-items: end;
  }
  .expense-list {
    list-style: none;
    margin: 0;
    padding: 0;
  }
  .expense {
    display: grid;
    grid-template-columns: 1fr auto auto auto;
    gap: 12px;
    align-items: center;
    padding: 10px 12px;
    border: 1px solid #e3e5ea;
    border-radius: 6px;
    margin-bottom: 8px;
    background: #fff;
  }
  .expense .exp-note {
    color: #555;
    font-size: 0.88rem;
    overflow: hidden;
    text-overflow: ellipsis;
    white-space: nowrap;
  }
  .expense .exp-amount {
    font-weight: 700;
    min-width: 70px;
    text-align: right;
  }
  .expense .exp-cat {
    background: #eef3ff;
    color: #2a4bbf;
    padding: 3px 8px;
    border-radius: 12px;
    font-size: 0.78rem;
    text-transform: capitalize;
  }
  .expense .exp-date {
    color: #666;
    font-size: 0.85rem;
    min-width: 90px;
  }
  .exp-del {
    width: auto;
    padding: 5px 10px;
    background: #fff;
    color: #b00020;
    border: 1px solid #e3c5c9;
    font-size: 0.82rem;
  }
  .exp-del:hover {
    background: #fde8ea;
  }
  .empty {
    color: #888;
    text-align: center;
    padding: 20px;
    font-size: 0.9rem;
  }
  @media (max-width: 600px) {
    .summary { grid-template-columns: 1fr; }
    .expense { grid-template-columns: 1fr auto; }
    .expense .exp-note, .expense .exp-date { grid-column: 1 / -1; }
  }
</style>
</head>
<body>
<div class="container">
  <h1>Personal Expense Tracker</h1>

  <section class="panel">
    <h2>Add Expense</h2>
    <form id="expense-form" novalidate>
      <div class="form-grid">
        <div>
          <label for="amount">Amount</label>
          <input type="number" id="amount" step="0.01" min="0.01" placeholder="0.00" inputmode="decimal">
        </div>
        <div>
          <label for="category">Category</label>
          <select id="category">
            <option value="groceries">Groceries</option>
            <option value="transport">Transport</option>
            <option value="bills">Bills</option>
            <option value="fun">Fun</option>
          </select>
        </div>
        <div>
          <label for="date">Date</label>
          <input type="date" id="date">
        </div>
        <div class="full">
          <label for="note">Note (optional)</label>
          <input type="text" id="note" placeholder="e.g. weekly groceries" maxlength="120">
        </div>
        <div class="full">
          <button type="submit" id="add-expense">Add Expense</button>
        </div>
      </div>
      <div id="form-error" class="form-error" role="alert"></div>
    </form>
  </section>

  <section class="panel">
    <h2>Filters</h2>
    <div class="filters">
      <div>
        <label for="filter-category">Category</label>
        <select id="filter-category">
          <option value="all">All</option>
          <option value="groceries">Groceries</option>
          <option value="transport">Transport</option>
          <option value="bills">Bills</option>
          <option value="fun">Fun</option>
        </select>
      </div>
      <div>
        <label for="filter-from">From date</label>
        <input type="date" id="filter-from">
      </div>
      <div>
        <label for="filter-to">To date</label>
        <input type="date" id="filter-to">
      </div>
      <div>
        <button type="button" class="secondary" id="clear-filters">Clear Filters</button>
      </div>
    </div>
  </section>

  <section class="panel">
    <div class="summary">
      <div class="total-box">
        <div class="label">Total (visible)</div>
        <div class="value" id="total">0.00</div>
      </div>
      <div>
        <h2 style="margin-bottom:8px;">By Category (visible)</h2>
        <div class="cat-list" id="cat-summary">
          <div class="cat-total" data-cat="groceries"><span class="cat-name">groceries</span><span class="cat-amount">0.00</span></div>
          <div class="cat-total" data-cat="transport"><span class="cat-name">transport</span><span class="cat-amount">0.00</span></div>
          <div class="cat-total" data-cat="bills"><span class="cat-name">bills</span><span class="cat-amount">0.00</span></div>
          <div class="cat-total" data-cat="fun"><span class="cat-name">fun</span><span class="cat-amount">0.00</span></div>
        </div>
      </div>
    </div>
  </section>

  <section class="panel">
    <h2>Expenses</h2>
    <ul id="expense-list" class="expense-list"></ul>
    <div id="empty-state" class="empty">No expenses yet. Add one above.</div>
  </section>
</div>

<script>
(function () {
  "use strict";

  var STORAGE_KEY = "expense_tracker_v1";
  var CATEGORIES = ["groceries", "transport", "bills", "fun"];

  var state = {
    expenses: []
  };

  // ---- DOM refs ----
  var form = document.getElementById("expense-form");
  var amountInput = document.getElementById("amount");
  var categoryInput = document.getElementById("category");
  var dateInput = document.getElementById("date");
  var noteInput = document.getElementById("note");
  var formError = document.getElementById("form-error");
  var listEl = document.getElementById("expense-list");
  var emptyState = document.getElementById("empty-state");
  var totalEl = document.getElementById("total");
  var catSummary = document.getElementById("cat-summary");
  var filterCategory = document.getElementById("filter-category");
  var filterFrom = document.getElementById("filter-from");
  var filterTo = document.getElementById("filter-to");
  var clearFiltersBtn = document.getElementById("clear-filters");

  // ---- Persistence ----
  function load() {
    try {
      var raw = localStorage.getItem(STORAGE_KEY);
      if (!raw) return;
      var parsed = JSON.parse(raw);
      if (Array.isArray(parsed)) {
        state.expenses = parsed.filter(function (e) {
          return e && typeof e.amount === "number" && typeof e.category === "string" && typeof e.date === "string";
        });
      }
    } catch (err) {
      state.expenses = [];
    }
  }

  function save() {
    try {
      localStorage.setItem(STORAGE_KEY, JSON.stringify(state.expenses));
    } catch (err) {
      // ignore quota errors
    }
  }

  // ---- Helpers ----
  function formatMoney(n) {
    return n.toFixed(2);
  }

  function setFormError(msg) {
    formError.textContent = msg || "";
  }

  function isMissingDate(d) {
    return !d || d.trim() === "";
  }

  // ---- Filtering ----
  function getFilteredExpenses() {
    var cat = filterCategory.value;
    var from = filterFrom.value;
    var to = filterTo.value;

    return state.expenses.filter(function (e) {
      if (cat !== "all" && e.category !== cat) return false;
      if (from && e.date < from) return false;
      if (to && e.date > to) return false;
      return true;
    });
  }

  // ---- Rendering ----
  function render() {
    // Sort newest first by date, then by id descending for stable order
    var sorted = state.expenses.slice().sort(function (a, b) {
      if (a.date === b.date) {
        return b.id - a.id;
      }
      return a.date < b.date ? 1 : -1;
    });

    listEl.innerHTML = "";

    if (sorted.length === 0) {
      emptyState.style.display = "block";
      emptyState.textContent = "No expenses yet. Add one above.";
    } else {
      emptyState.style.display = "none";
    }

    var cat = filterCategory.value;
    var from = filterFrom.value;
    var to = filterTo.value;

    var visibleTotal = 0;
    var catTotals = {};
    CATEGORIES.forEach(function (c) { catTotals[c] = 0; });

    sorted.forEach(function (e) {
      var visible = true;
      if (cat !== "all" && e.category !== cat) visible = false;
      if (from && e.date < from) visible = false;
      if (to && e.date > to) visible = false;

      var li = document.createElement("li");
      li.className = "expense";
      li.style.display = visible ? "grid" : "none";
      li.dataset.id = e.id;

      var noteSpan = document.createElement("span");
      noteSpan.className = "exp-note";
      noteSpan.textContent = e.note || "";

      var amountSpan = document.createElement("span");
      amountSpan.className = "exp-amount";
      amountSpan.textContent = formatMoney(e.amount);

      var catSpan = document.createElement("span");
      catSpan.className = "exp-cat";
      catSpan.textContent = e.category;

      var dateSpan = document.createElement("span");
      dateSpan.className = "exp-date";
      dateSpan.textContent = e.date;

      var delBtn = document.createElement("button");
      delBtn.type = "button";
      delBtn.className = "exp-del";
      delBtn.textContent = "Delete";
      delBtn.addEventListener("click", function () {
        deleteExpense(e.id);
      });

      li.appendChild(noteSpan);
      li.appendChild(catSpan);
      li.appendChild(dateSpan);
      li.appendChild(amountSpan);
      li.appendChild(delBtn);

      listEl.appendChild(li);

      if (visible) {
        visibleTotal += e.amount;
        if (catTotals.hasOwnProperty(e.category)) {
          catTotals[e.category] += e.amount;
        }
      }
    });

    totalEl.textContent = formatMoney(visibleTotal);

    CATEGORIES.forEach(function (c) {
      var el = catSummary.querySelector('.cat-total[data-cat="' + c + '"]');
      if (el) {
        var amountEl = el.querySelector(".cat-amount");
        if (amountEl) {
          amountEl.textContent = formatMoney(catTotals[c]);
        } else {
          el.textContent = c + ": " + formatMoney(catTotals[c]);
        }
      }
    });

    // If no visible rows but there are expenses (all filtered out), show message
    if (sorted.length > 0) {
      var anyVisible = false;
      for (var i = 0; i < listEl.children.length; i++) {
        if (listEl.children[i].style.display !== "none") {
          anyVisible = true;
          break;
        }
      }
      if (!anyVisible) {
        emptyState.style.display = "block";
        emptyState.textContent = "No expenses match the current filters.";
      }
    }
  }

  // ---- Actions ----
  function addExpense(amount, category, date, note) {
    var expense = {
      id: Date.now() + Math.floor(Math.random() * 1000),
      amount: amount,
      category: category,
      date: date,
      note: note || ""
    };
    state.expenses.push(expense);
    save();
    render();
  }

  function deleteExpense(id) {
    state.expenses = state.expenses.filter(function (e) { return e.id !== id; });
    save();
    render();
  }

  // ---- Form submit ----
  form.addEventListener("submit", function (evt) {
    evt.preventDefault();
    var rawAmount = amountInput.value;
    var amountNum = parseFloat(rawAmount);
    var category = categoryInput.value;
    var date = dateInput.value;
    var note = noteInput.value;

    // Validation
    if (rawAmount === "" || rawAmount === null || isNaN(amountNum) || !isFinite(amountNum)) {
      setFormError("Please enter a valid numeric amount.");
      return;
    }
    if (amountNum === 0) {
      setFormError("Amount must be greater than zero.");
      return;
    }
    if (amountNum < 0) {
      setFormError("Amount cannot be negative.");
      return;
    }
    if (isMissingDate(date)) {
      setFormError("Please choose a date.");
      return;
    }

    // Round to 2 decimals to avoid float noise
    var rounded = Math.round(amountNum * 100) / 100;

    addExpense(rounded, category, date, note.trim());
    setFormError("");
    amountInput.value = "";
    amountInput.focus();
  });

  // ---- Filters ----
  filterCategory.addEventListener("change", render);
  filterFrom.addEventListener("change", render);
  filterTo.addEventListener("change", render);
  clearFiltersBtn.addEventListener("click", function () {
    filterCategory.value = "all";
    filterFrom.value = "";
    filterTo.value = "";
    render();
  });

  // ---- Init ----
  // Default date to today for convenience
  try {
    var today = new Date();
    var yyyy = today.getFullYear();
    var mm = String(today.getMonth() + 1).padStart(2, "0");
    var dd = String(today.getDate()).padStart(2, "0");
    dateInput.value = yyyy + "-" + mm + "-" + dd;
  } catch (e) {}

  load();
  render();
})();
</script>
</body>
</html>
